package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.body.VariableDeclarator;
import com.github.javaparser.ast.expr.AnnotationExpr;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.printer.DefaultPrettyPrinter;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;
import java.util.stream.Stream;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length != 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];
        Path sourcePath = Paths.get(sourceDirectory);

        if (!Files.exists(sourcePath)) {
            System.err.println("Source directory does not exist: " + sourceDirectory);
            System.exit(1);
        }

        // Process all Java files in the directory recursively
        try (Stream<Path> paths = Files.walk(sourcePath)
                .filter(Files::isRegularFile)
                .filter(path -> path.toString().endsWith(".java"))) {

            paths.forEach(Main::processJavaFile);
        }
    }

    private static void processJavaFile(Path javaFilePath) {
        try {
            // Parse the Java file
            CompilationUnit cu = StaticJavaParser.parse(javaFilePath.toFile());
            boolean modified = false;

            // Process imports
            modified |= processImports(cu);

            // Process annotations
            modified |= processAnnotations(cu);

            if (modified) {
                // Save the modified file
                cu.save(javaFilePath.toFile());
                System.out.println("Modified: " + javaFilePath);
            }
        } catch (Exception e) {
            System.err.println("Error processing file " + javaFilePath + ": " + e.getMessage());
        }
    }

    private static boolean processImports(CompilationUnit cu) {
        boolean modified = false;
        NodeList<ImportDeclaration> imports = cu.getImports();

        for (ImportDeclaration importDecl : imports) {
            Name name = importDecl.getName();
            String nameStr = name.asString();
            // Check if it's a javax.jws import
            if (nameStr.startsWith("javax.jws")) {
                // Replace with jakarta.jws
                String newQualifiedName = nameStr.replace("javax.jws", "jakarta.jws");
                importDecl.setName(newQualifiedName);
                modified = true;
            }
        }

        return modified;
    }

    private static boolean processAnnotations(CompilationUnit cu) {
        boolean modified = false;

        // Get all annotations in the file
        List<AnnotationExpr> annotations = cu.findAll(AnnotationExpr.class);

        for (AnnotationExpr annotation : annotations) {
            Name name = annotation.getName();
            String nameStr = name.asString();
            // Check if it's a javax.jws annotation
            if (nameStr.startsWith("javax.jws")) {
                // Replace with jakarta.jws
                String newQualifiedName = nameStr.replace("javax.jws", "jakarta.jws");
                annotation.setName(newQualifiedName);
                modified = true;
            }
        }

        return modified;
    }
}

